+/**
+ * Preferences service — manages user notification preferences.
+ *
+ * Provides CRUD operations for user notification preferences and
+ * a shouldSend() method that the NotificationService uses to check
+ * whether a notification should be delivered to a given user.
+ *
+ * Storage: In-memory Map keyed by userId. Default preferences are
+ * created on first access (lazy initialization).
+ */
+
+import type { NotificationType } from '../models/notification.js';
+import type { EmailFrequency, UpdatePreferencesInput, UserPreferences } from '../models/user-preferences.js';
+import { createDefaultPreferences } from '../models/user-preferences.js';
+import { Logger } from '../utils/logger.js';
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+  private preferences: Map<string, UserPreferences> = new Map();
+
+  /**
+   * Get preferences for a user. If none exist, creates and stores defaults.
+   */
+  getPreferences(userId: string): UserPreferences {
+    let prefs = this.preferences.get(userId);
+    if (!prefs) {
+      this.logger.info(`Creating default preferences for user ${userId}`);
+      prefs = createDefaultPreferences(userId);
+      this.preferences.set(userId, prefs);
+    }
+    return { ...prefs, email: { ...prefs.email, categories: [...prefs.email.categories] } };
+  }
+
+  /**
+   * Update preferences for a user. Merges provided fields with existing preferences.
+   */
+  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
+    const current = this.getPreferences(userId);
+
+    if (input.email) {
+      if (input.email.enabled !== undefined) {
+        current.email.enabled = input.email.enabled;
+      }
+      if (input.email.categories !== undefined) {
+        current.email.categories = [...input.email.categories];
+      }
+      if (input.email.frequency !== undefined) {
+        current.email.frequency = input.email.frequency;
+      }
+    }
+
+    current.updatedAt = new Date();
+    this.preferences.set(userId, current);
+
+    this.logger.info(`Updated preferences for user ${userId}`);
+    return { ...current, email: { ...current.email, categories: [...current.email.categories] } };
+  }
+
+  /**
+   * Check whether a notification should be sent to a user via email.
+   *
+   * Returns false if:
+   * - Email is globally disabled for the user
+   * - The notification type is not in the user's subscribed categories
+   *
+   * Note: frequency filtering (digest batching) is not enforced here —
+   * it would be handled by a separate digest/scheduler system.
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
+    const prefs = this.getPreferences(userId);
+
+    if (!prefs.email.enabled) {
+      this.logger.info(`Email disabled for user ${userId}, suppressing ${notificationType}`);
+      return false;
+    }
+
+    if (!prefs.email.categories.includes(notificationType)) {
+      this.logger.info(`User ${userId} not subscribed to ${notificationType}, suppressing`);
+      return false;
+    }
+
+    return true;
+  }
+
+  /**
+   * Get the email frequency setting for a user.
+   */
+  getEmailFrequency(userId: string): EmailFrequency {
+    return this.getPreferences(userId).email.frequency;
+  }
+
+  /**
+   * Delete preferences for a user (e.g., on account deletion).
+   */
+  deletePreferences(userId: string): boolean {
+    return this.preferences.delete(userId);
+  }
+
+  /**
+   * Clear all stored preferences (useful for testing).
+   */
+  clear(): void {
+    this.preferences.clear();
+  }
+}

