+    it('should return the same preferences on subsequent calls', () => {
+      const first = service.getPreferences('user-1');
+      const second = service.getPreferences('user-1');
+
+      expect(first.userId).toBe(second.userId);
+      expect(first.email.enabled).toBe(second.email.enabled);
+      expect(first.email.categories).toEqual(second.email.categories);
+      expect(first.email.frequency).toBe(second.email.frequency);
+    });
+
+    it('should return independent copies (not references)', () => {
