/**
 * Send a notification through the appropriate adapter.
 * If a PreferencesService is configured and a userId is provided,
 * user preferences are checked before sending. If the user has
 * disabled the notification type or channel, the notification is suppressed.
 *
 * If no adapter is registered for the channel, the notification is still
 * recorded (for testing/audit) but no delivery is attempted.
 */
private async sendNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  userId?: string;
}): Promise<void> {
  // Check user preferences before sending
  if (this.preferencesService && params.userId && params.channel === 'email') {
    if (!this.preferencesService.shouldSendEmail(params.userId, params.type)) {
      this.logger.info(
        `Notification suppressed for user ${params.userId}: ${params.type} via ${params.channel}`,
      );
      return;
    }
  }

  const id = generateNotificationId();
  const now = new Date();

  const notification: Notification = {
    id,
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: now,
  };
  this.notifications.push(notification);

  const adapter = this.adapters.get(params.channel);
  if (adapter) {
    const payload: NotificationPayload = {
      id,
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      metadata: params.metadata,
      createdAt: now,
    };

    const result = await adapter.send(payload);
    this.results.push(result);
    this.logger.info(`Notification ${id} delivered via ${params.channel}: success=${result.success}`);
  } else {
    this.logger.info(`Notification ${id} recorded (no adapter for channel: ${params.channel})`);
  }
}

